class Solution {
    public int integerReplacement(int n) {
        long N = n;
        int operations = 0;
        while (N != 1) {
            if (N % 2 == 0) {
                N /= 2;
            } else if (N % 4 == 1 || N == 3) {
                N -= 1;
            } else {
                N += 1;
            }
            operations++;
        }
        return operations;
    }
}
```
